var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"이번 도전자는 VIP 카드를 3개나 모은 실력자들입니다! 베팅에 참고가 되겠군요!","JPN":"今度の挑戦者はVIPカードを三つも集めた実力者たちです！　ベッティングの参考にしてください！","ENG":"These challengers have already claimed 3 VIP cards! That should help you placing your bets!","TWN":"這次的挑戰者實力非常堅強，她們已經收集到3張VIP！供大家下注時參考！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"하지만 다들 잊지 않으셨겠죠? 이런 상황이 지난번에도 있었다는 사실을요!","JPN":"しかし、皆さん忘れていませんよね？　以前にもこんな状況があったという事実を！","ENG":"But don’t forget! We had a similar situation like this last time as well!","TWN":"但大家應該還沒忘記吧？上次也有過相同的情況！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"헤이븐 랜드를 노리고 온갖 더럽고 치졸한 수법을 썼던 놈들이 있었죠!","JPN":"ヘイブンランドを狙い、汚く幼稚な手法の数々を使ってきたやつらがいましたね！","ENG":"Those guys who used all sorts of dirty tricks to take over Havenland!","TWN":"那些人用非常骯髒的手段想要得到天堂樂園！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"하지만 우리의 헤이븐 형님! 아끼시는 무기에 피 한 방울 안 묻히고 죄다 TKO승!","JPN":"ですが、さすが我らのヘイブン様！　大事にしている武器に血一滴もつけずに全部TKO勝利したんでした！","ENG":"But Mr. Haven defeated them with a TKO without even using his weapon!","TWN":"但我們的天堂大哥！用他心愛的武器，完全沒流一滴血就TKO勝！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"아, 지금 뭔가 얘기가 오가는데요?","JPN":"あ、今何か会話が交わされているようですね？","ENG":"Huh? It seems like Mr. Haven is talking to the contestants!","TWN":"喔？他們現在好像在說什麼呢？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"자비로우신 헤이븐 님! 조심하라고 당부해 주시는 걸까요?","JPN":"慈悲深いヘイブン様！　気をつけろとでも言っているのでしょうか？","ENG":"Merciful Mr. Haven! Is he warning them to be careful?","TWN":"仁慈的天堂大哥！是在叮嚀對手要小心嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"나는 누나에게……. 아니, 헤론에게 빚을 졌어.","JPN":"僕は姉さん……いや、ヘロンに借りがあるんだ。","ENG":"I owe my sister... I mean, Heron.","TWN":"這是我欠姊……不對，是我欠海倫的。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"그러니까 미안해, 친구들. 놀이는 여기까지야.","JPN":"だからごめん、みんな。遊びはここまでだ。","ENG":"I'm sorry everyone. But playtime's over.","TWN":"所以朋友們，抱歉，遊戲到此為止。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"너 이 자식…….","JPN":"こいつ……","ENG":"You bastard...","TWN":"你這傢伙……"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아니야! 그런 게 어딨어?","JPN":"ううん！　そんなのダメだよ！","ENG":"No! You can't do that!","TWN":"不是這樣的！哪有這種事？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"내가 나로서 가치가 있는 것처럼, 너도 너로서 가치가 있는 거야.","JPN":"私が私として価値があるように、あなたもあなたとしての価値があるんだよ。","ENG":"Just as I am valuable for who I am, you are valuable for who you are, too.","TWN":"我有屬於我的價值，你也有屬於你的價值。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"다른 사람을 무서워하면 안 돼, 루트. 네 삶의 가치를 믿어 줄 수 있는 사람은 너뿐이야.","JPN":"他の人に怯えちゃダメ、ルート。人生の価値を信じてあげられるのは自分だけなんだよ。","ENG":"You don't need to be afraid of others, Root. The only person who knows your worth is you.","TWN":"不可以畏懼其他人，路特。能夠相信你人生價值的人就只有你。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"우리의 천하무적 보스께서 저 어린 것들을 어떻게 짓밟아 주실지 기대되십니까?!","JPN":"天下無敵のボスが、あの子どもたちをどうやって踏みにじってくれるのか、期待で胸が高まりますね！？","ENG":"Aren't you excited to see how our undefeated boss will stomp on those little kids?!","TWN":"究竟我們天下無敵的BOSS會如何輾壓她們呢？大家期待嗎？！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"두 눈 크게 뜨고 확인하시죠! 경기 시작하겠습니다!","JPN":"両目をこらしてご確認ください！　試合、スタート！","ENG":"Keep your eyes peeled, you don’t want to miss this! The match has begun!","TWN":"睜大眼睛看好囉！比賽開始！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"……가치라고 했어, 시그마?","JPN":"……価値って言った？　シグマ。","ENG":"...Did you say, ”valuable\\", Sigma?","TWN":"……西格瑪，你說價值？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"나는 저들이 바라는 대로 움직여 줄 수밖에 없어.","JPN":"僕はあの人たちが望むとおりに動くしかないんだ。","ENG":"I'm a puppet that does what I am told.","TWN":"我只能照他們所期待的去做。"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"그렇지 않으면…… 남는 건 아무 도움도 되지 않고 놀기만 좋아할 뿐인 겁쟁이니까.","JPN":"そうじゃないと……なんの役にも立たない、ただの遊び好きな臆病者でしかないから。","ENG":"If I don't... then all I am is just a coward who is of no help, and only loves to have fun.","TWN":"否則……我就只是一個什麼忙也幫不上，只知道玩的膽小鬼。"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_MASK","text":{"KOREA":"그러니까, 어서 덤벼!","JPN":"だから、早くかかってこい！","ENG":"So come at me!","TWN":"你們快出招吧！"},"stage":{"bg":"COLOSSEUM","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_MASK","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};